  SELECT COUNT(1) FROM post_topic pt JOIN post p ON p.id=pt.post_id
  WHERE pt.topic_id=t.id AND p.audit_status=1 AND p.status=1 AND p.is_deleted=FALSE
),updated_at=CURRENT_TIMESTAMP
WHERE t.id IN
#{topicId}

