SELECT  FROM topic t
LEFT JOIN topic_hot_snapshot s ON s.topic_id=t.id
WHERE t.region=#{region}
AND t.status=#{status}
AND t.recommended=#{recommended}
AND t.name LIKE CONCAT('%',#{keyword},'%')
ORDER BY t.pinned_sort DESC,t.id DESC LIMIT #{limit} OFFSET #{offset}

